        &self.name
    }
fn lerp_lut(lut: &[f32], x: f32) -> f32 {
    let n = lut.len();
    if n == 0 { return x; }
    let x = x.clamp(0.0, 1.0);
    let pos = x * (n - 1) as f32;
    let lo = (pos as usize).min(n - 2);
    let hi = lo + 1;
    let frac = pos - lo as f32;
    lut[lo] * (1.0 - frac) + lut[hi] * frac
}
